<template>
  <v-container>
    <v-label
      icon="mdi-handshake-outline"
      class="mb-8 text-md-h5 text-center"
      label="Devenez notre partenaire"
    ></v-label>
    <v-text class="text-subtitle font-italic">
      NB: Selectionnez votre statut avant de remplir le formulaire
    </v-text>
    <v-tabs
      class="my-4"
      icons-and-text
      background-color="primary lighten-2"
      fixed-tabs
      center-active
    >
      <v-tab
        @click="
          proprio = true;
          guide = false;
          vendeur = false;
        "
        >Proprietaire</v-tab
      >
      <v-tab
        @click="
          proprio = false;
          guide = true;
          vendeur = false;
        "
        >Guide</v-tab
      >
      <v-tab
        @click="
          proprio = false;
          guide = false;
          vendeur = true;
        "
        >Vendeur</v-tab
      >
    </v-tabs>
    <template>
      <v-form @submit="Envorey_formulaire()">
        <v-card
          max-width="850"
          class="mx-auto grey py-10 lighten-4 mt-5 px-5 mb-10"
        >
          <v-card-title class="primary--text"
            ><v-texte class="mx-auto text-uppercase">
              Formulaire d'inscription</v-texte
            ></v-card-title
          >
          <v-divider></v-divider>
          <v-card-text>
            <v-row>
              <!-- nom et prenoms -->
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  v-model="nom"
                  :rules="[rules.required]"
                  prepend-icon="mdi-account"
                  hint="Votre nom à l'État Civil"
                  label="Nom légal*"
                  required
                ></v-text-field>
              </v-col>
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  v-model="prenom"
                  :rules="[rules.required]"
                  prepend-icon="mdi-account"
                  hint="Vos prénom à l'État Civil"
                  label="Prénoms légaux*"
                  required
                ></v-text-field>
              </v-col>
              <!-- contacts et email -->
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  v-model="contact"
                  counter
                  :rules="[rules.max, rules.required]"
                  prepend-icon="mdi-cellphone"
                  type="tel"
                  hint="Numéro de telephone"
                  label="Numéro de telephone*"
                  required
                ></v-text-field>
              </v-col>
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  :rules="[rules.required, rules.email]"
                  v-model="email"
                  type="email"
                  prepend-icon="mdi-email"
                  hint="Votre adresse email"
                  placeholder="example@gmail.com"
                  label="Adresse E-mail*"
                  required
                ></v-text-field>
              </v-col>
              <!-- ville et mot de pass -->
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  v-model="ville"
                  :rules="[rules.required]"
                  prepend-icon="mdi-city"
                  hint="La ville où vous travaillez"
                  label="Ville*"
                  required
                ></v-text-field>
              </v-col>

              <!-- proprio special fields -->
              <v-col v-if="proprio" cols="12" sm="12" md="6">
                <v-autocomplete
                  v-model="country"
                  :items="countries"
                  :rules="[rules.required]"
                  label="Catégorie*"
                  placeholder="Selectionner..."
                ></v-autocomplete>
              </v-col>
            </v-row>
            <!-- mots de pass -->
            <v-row>
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  v-model="password"
                  :append-icon="show1 ? 'mdi-eye' : 'mdi-eye-off'"
                  :rules="[rules.required, rules.min]"
                  :type="show1 ? 'text' : 'password'"
                  name="input-10-1"
                  label="Mot de pass"
                  hint="Au moins 8 caractères"
                  counter
                  @click:append="show1 = !show1"
                ></v-text-field>
              </v-col>
              <v-col cols="12" md="6" sm="12">
                <v-text-field
                  required
                  :append-icon="show3 ? 'mdi-eye' : 'mdi-eye-off'"
                  :rules="[rules.required]"
                  :type="show3 ? 'text' : 'password'"
                  name="input-10-1"
                  label="Confirmer le mot de pass"
                  hint="Repeter le mot de pass"
                  @click:append="show3 = !show3"
                ></v-text-field>
              </v-col>
            </v-row>

            <v-row>
              <!-- proprio special fields -->
              <v-col v-if="proprio" cols="12" sm="12" md="12">
                <v-textarea
                  prepend-icon="mdi-message"
                  :rules="[rules.required]"
                  label="Décrivez votre activité"
                  auto-grow
                ></v-textarea>
              </v-col>
              <!-- guide special fields -->
              <v-col v-if="guide" cols="12" sm="12" md="12">
                <v-textarea
                  prepend-icon="mdi-message"
                  :rules="[rules.required]"
                  label="Décrivez vous en quelques mots"
                  auto-grow
                ></v-textarea>
              </v-col>
              <!-- vendeur special fields -->
              <v-col v-if="vendeur" cols="12" sm="12" md="12">
                <v-textarea
                  prepend-icon="mdi-message"
                  :rules="[rules.required]"
                  label="Décrivez votre activité"
                  auto-grow
                ></v-textarea>
              </v-col>
            </v-row>
          </v-card-text>
          <v-card-action>
            <v-btn @click="Envorey_formulaire()"> envoyer </v-btn>
          </v-card-action>
        </v-card>
      </v-form>
    </template>
  </v-container>
</template>

<script>
//import AuthForm from "../components/AuthForm.vue";
import VLabel from "../components/Label.vue";
export default {
  components: { VLabel },
  data: () => ({
    //tabs controle
    identite: "",
    proprio: true,
    contact: "",
    guide: false,
    show1: false,
    show3: false,
    password: "",
    rules: {
      required: (value) => !!value || "Ce champ est obligatoire.",
      min: (v) => v.length >= 8 || "Min 8 characters",
      max: (v) => (v.length >= 10) & (v.length <= 10) || "Numero a 10 choffres",
      confirmer: (value) =>
        value == this.password || "Mots de pass non identiques",
      emailMatch: () => `The email and password you entered don't match`,
      counter: (value) => value.length <= 20 || "Max 20 characters",
      email: (value) => {
        const pattern =
          /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
        return pattern.test(value) || "Invalid e-mail.";
      },
    },
    vendeur: false,
    countries: ["Afghanistan", "Albania", "Algeria", "Andorra", "Angola"],
    country: null,
  }),

  methods: {
    Envorey_formulaire() {
      let proprio2 = this.proprio;
      let guide2 = this.guide;
      let vendeur2 = this.vendeur;

      if (proprio2) {
        this.identite = "Proprio";
        alert(this.identite);
      } else if (vendeur2) {
        this.identite = "Vendeur";
        alert(this.identite);
      } else if (guide2) {
        this.identite = "Guide";
        alert(this.identite);
      }
    },
  },
};
</script>

