import Vue from "vue";
import VueRouter from "vue-router";
import Home from "../views/Home.vue";
import Auth from "../views/AuthPage.vue";
import Contact from "../views/About.vue";
import Market from "../views/MarketPage.vue";
import Lieux from "../views/Lieux.vue";

//Services  routes

import AgroTourisme from "../views/Services/AgroTourisme.vue";
import ArtTourisme from "../views/Services/ArtTourisme.vue";
import EcoTourisme from "../views/Services/EcoTourisme.vue";
import GastroTourisme from "../views/Services/GastroTourisme.vue";
import Guide from "../views/Services/Guide.vue";
import Hotel from "../views/Services/Hotel.vue";

// Special  routes

import DetailProduit from "../views/MarketViews/DetailProduit.vue";

Vue.use(VueRouter);

const routes = [
  {
    path: "/",
    name: "Home",
    component: Home,
  },
  {
    path: "/auth",
    name: "Auth",
    component: Auth,
  },
  {
    path: "/contact",
    name: "Contact",
    component: Contact,
  },
  {
    path: "/market",
    name: "Market",
    component: Market,
  },

  // Services routes

  {
    path: "/lieux",
    name: "Lieux",
    component: Lieux,
  }, {
    path: "/agroTourisme",
    name: "AgroTourisme",
    component: AgroTourisme,
  },
  {
    path: "/artTourisme",
    name: "ArtTourisme",
    component: ArtTourisme,
  },
  {
    path: "/ecoTourisme",
    name: "EcoTourisme",
    component: EcoTourisme,
  },
  {
    path: "/gastroTourisme",
    name: "GastroTourisme",
    component: GastroTourisme,
  },
  {
    path: "/guide",
    name: "Guide",
    component: Guide,
  },
  {
    path: "/hotel",
    name: "Hotel",
    component: Hotel,
  },

  // Special routes

  {
    path:"/detailproduit",
    name: "Detail Produit",
    component: DetailProduit,
  }
];

const router = new VueRouter({
  mode: "history",
  base: process.env.BASE_URL,
  routes,
});

export default router;
